INSERT INTO public.characters (id, user_id, type, data, name) VALUES ('72f0818d-aec0-4e76-8a56-43bad1c9e8de', '31fa4150-9464-43c5-90c8-5ea5cfc664d7', 'NPC', '{"ac": 7, "hd": 5, "hp": 0, "xp": 0, "name": "Halcon", "save": 1, "class": "", "npcType": "Beast", "picture": "", "equipment": [], "bonusToHit": 1, "description": "Save. +4 relacionado al viento\\nDaño 1d2\\nInv. 2 espacios\\nSpecial Abilities:\\n    •    Long-Distance Flight: Can fly up to 150 miles/day without rest, depending on weather.\\n    •    Homing Instinct: 95% chance to reach its target if the destination is known and reachable. In harsh weather, reduce to 75%.\\n    •    Dive Attack: If ordered to attack while airborne, the falcon may dive to strike (once), gaining +2 to hit. Damage increases to 1d4, then it must break away.\\n    •    Handler Bonding: Falcons raised and bonded with a handler gain +4 morale and a 5% bonus to success on message delivery.\\n    •    Return to Sender: On delivery, a trained falcon will wait for up to 1 hour, then return to the sender if not dismissed.", "proficiencies": [], "openFieldMovement": 480, "closeQuarterMovement": 120, "nonWeaponProficiencies": [{"name": "WeatherSense", "value": 70}, {"name": "AltitudeAdaptation", "value": 70}, {"name": "Observation", "value": 40}, {"name": "Tracking", "value": 70}]}', 'Halcon');
